mapper.select:
SELECT ri.id, ri.room_number, ri.rent, ri.apartment_id, ai.name AS apartment_name, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude FROM room_info ri LEFT JOIN apartment_info ai ON ri.apartment_id = ai.id AND ai.is_deleted = 0 AND ai.is_release = 1 WHERE ri.is_deleted = 0 AND ri.is_release = 1
AND ai.province_id = #{queryVo.provinceId}
AND ai.city_id = #{queryVo.cityId}
AND ai.district_id = #{queryVo.districtId}
AND ri.apartment_id = #{queryVo.apartmentId}
AND ri.rent >= #{queryVo.minRent}
AND ri.rent <= #{queryVo.maxRent}
ORDER BY ri.id DESC
